// Debug action log (shown in F9 panel)
interface DebugLogEntry {
  time: number
  type: 'info' | 'success' | 'error' | 'warning'
  action: string
  details?: string
}
const debugActionLog: DebugLogEntry[] = []
const MAX_DEBUG_LOG_ENTRIES = 50

function addDebugLog(type: DebugLogEntry['type'], action: string, details?: string) {
  debugActionLog.unshift({
    time: Date.now(),
    type,
    action,
    details
  })
  // Keep only the last N entries
  if (debugActionLog.length > MAX_DEBUG_LOG_ENTRIES) {
    debugActionLog.pop()
  }
  // Also log to console
  const prefix = type === 'error' ? '[DEBUG ERROR]' : type === 'warning' ? '[DEBUG WARN]' : '[DEBUG]'
  console.log(prefix, action, details || '')
}

// Apply game mode visual effects
function applyGameModeEffects() {
  // Clear any existing intervals
  gameModeIntervals.forEach(id => clearInterval(id))
  gameModeIntervals = []

  // Remove existing game mode styles
  const existingStyle = document.getElementById('game-mode-styles')
  if (existingStyle) existingStyle.remove()

  // Remove existing overlays
  document.querySelectorAll('.game-mode-overlay').forEach(el => el.remove())

  if (activeGameModes.length === 0) return

  // Add CSS for game modes
  const style = document.createElement('style')
  style.id = 'game-mode-styles'
  style.textContent = `
    /* Disco Mode */
    @keyframes disco-bg {
      0% { filter: hue-rotate(0deg); }
      100% { filter: hue-rotate(360deg); }
    }
    .disco-mode #app {
      animation: disco-bg 2s linear infinite;
    }
    .disco-mode .disco-ball {
      position: fixed;
      top: 10px;
      right: 10px;
      font-size: 40px;
      animation: disco-spin 1s linear infinite;
      z-index: 1000;
      pointer-events: none;
    }
    @keyframes disco-spin {
      0% { transform: rotate(0deg) scale(1); }
      50% { transform: rotate(180deg) scale(1.2); }
      100% { transform: rotate(360deg) scale(1); }
    }

    /* Rainbow Mode */
    @keyframes rainbow-border {
      0% { border-color: red; }
      14% { border-color: orange; }
      28% { border-color: yellow; }
      42% { border-color: green; }
      57% { border-color: blue; }
      71% { border-color: indigo; }
      85% { border-color: violet; }
      100% { border-color: red; }
    }
    .rainbow-mode svg {
      border: 4px solid red;
      animation: rainbow-border 3s linear infinite;
      border-radius: 8px;
    }

    /* Earthquake Mode */
    @keyframes earthquake {
      0%, 100% { transform: translate(0, 0) rotate(0deg); }
      10% { transform: translate(-2px, -1px) rotate(-0.5deg); }
      20% { transform: translate(2px, 1px) rotate(0.5deg); }
      30% { transform: translate(-1px, 2px) rotate(-0.3deg); }
      40% { transform: translate(1px, -2px) rotate(0.3deg); }
      50% { transform: translate(-2px, 1px) rotate(-0.5deg); }
      60% { transform: translate(2px, -1px) rotate(0.5deg); }
      70% { transform: translate(-1px, -2px) rotate(-0.3deg); }
      80% { transform: translate(1px, 2px) rotate(0.3deg); }
      90% { transform: translate(-2px, -1px) rotate(-0.5deg); }
    }
    .earthquake-mode #board-container {
      animation: earthquake 0.5s ease-in-out infinite;
    }

    /* Matrix Mode */
    .matrix-mode #app {
      background: black !important;
    }
    .matrix-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      pointer-events: none;
      z-index: 999;
      overflow: hidden;
      opacity: 0.3;
    }
    .matrix-drop {
      position: absolute;
      color: #00ff00;
      font-family: monospace;
      font-size: 14px;
      text-shadow: 0 0 5px #00ff00;
      white-space: pre;
      line-height: 1.2;
    }

    /* Giant Mode */
    .giant-mode svg {
      transform: scale(1.3);
      transform-origin: center top;
    }

    /* Tiny Mode */
    .tiny-mode svg {
      transform: scale(0.6);
    }

    /* Chaos Mode */
    @keyframes chaos-glitch {
      0%, 100% { filter: none; transform: none; }
      10% { filter: invert(1); }
      20% { transform: skewX(5deg); }
      30% { filter: hue-rotate(90deg); }
      40% { transform: skewY(-3deg); }
      50% { filter: saturate(3); }
      60% { transform: scale(1.02); }
      70% { filter: contrast(1.5); }
      80% { transform: translateX(2px); }
      90% { filter: blur(1px); }
    }
    .chaos-mode #board-container {
      animation: chaos-glitch 3s ease-in-out infinite;
    }

    /* Mirror Mode */
    .mirror-mode svg {
      transform: scaleX(-1);
    }

    /* Speed Mode */
    .speed-mode * {
      transition-duration: 0.1s !important;
      animation-duration: 0.5s !important;
    }
    .speed-mode::after {
      content: '⚡ SPEED MODE ⚡';
      position: fixed;
      top: 5px;
      left: 50%;
      transform: translateX(-50%);
      color: yellow;
      font-weight: bold;
      font-size: 12px;
      z-index: 1000;
      text-shadow: 0 0 5px orange;
      pointer-events: none;
    }

    /* Jumpscare overlay */
    .jumpscare-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: black;
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 9999;
      animation: jumpscare-flash 0.3s ease-out;
    }
    .jumpscare-overlay span {
      font-size: 200px;
      animation: jumpscare-shake 0.3s ease-out;
    }
    @keyframes jumpscare-flash {
      0% { opacity: 0; }
      50% { opacity: 1; }
      100% { opacity: 0; }
    }
    @keyframes jumpscare-shake {
      0%, 100% { transform: scale(1) rotate(0deg); }
      25% { transform: scale(1.5) rotate(-10deg); }
      50% { transform: scale(2) rotate(10deg); }
      75% { transform: scale(1.5) rotate(-5deg); }
    }
  `
  document.head.appendChild(style)

  const body = document.body

  // Apply mode classes
  if (activeGameModes.includes('disco')) {
    body.classList.add('disco-mode')
    // Add disco ball
    const discoBall = document.createElement('div')
    discoBall.className = 'disco-ball game-mode-overlay'
    discoBall.textContent = '🪩'
    document.body.appendChild(discoBall)
  }

  if (activeGameModes.includes('rainbow')) {
    body.classList.add('rainbow-mode')
  }

  if (activeGameModes.includes('earthquake')) {
    body.classList.add('earthquake-mode')
  }

  if (activeGameModes.includes('giant')) {
    body.classList.add('giant-mode')
  }

  if (activeGameModes.includes('tiny')) {
    body.classList.add('tiny-mode')
  }

  if (activeGameModes.includes('chaos')) {
    body.classList.add('chaos-mode')
  }

  if (activeGameModes.includes('mirror')) {
    body.classList.add('mirror-mode')
  }

  if (activeGameModes.includes('speed')) {
    body.classList.add('speed-mode')
  }

  if (activeGameModes.includes('matrix')) {
    body.classList.add('matrix-mode')
    // Create matrix rain overlay
    const matrixOverlay = document.createElement('div')
    matrixOverlay.className = 'matrix-overlay game-mode-overlay'
    matrixOverlay.id = 'matrix-rain'
    document.body.appendChild(matrixOverlay)

    // Initialize matrix drops
    matrixDrops = []
    for (let i = 0; i < 30; i++) {
      matrixDrops.push({
        x: Math.random() * window.innerWidth,
        y: Math.random() * -500,
        speed: 2 + Math.random() * 5,
        chars: Array(15).fill(0).map(() => String.fromCharCode(0x30A0 + Math.random() * 96))
      })
    }

    // Animate matrix rain
    const matrixInterval = setInterval(() => {
      const overlay = document.getElementById('matrix-rain')
      if (!overlay || !activeGameModes.includes('matrix')) {
        clearInterval(matrixInterval)
        return
      }

      overlay.innerHTML = matrixDrops.map(drop => {
        drop.y += drop.speed
        if (drop.y > window.innerHeight) {
          drop.y = -200
          drop.x = Math.random() * window.innerWidth
        }
        // Rotate chars occasionally
        if (Math.random() < 0.1) {
          drop.chars[Math.floor(Math.random() * drop.chars.length)] = String.fromCharCode(0x30A0 + Math.random() * 96)
        }
        return `<div class="matrix-drop" style="left:${drop.x}px;top:${drop.y}px">${drop.chars.join('\n')}</div>`
      }).join('')
    }, 50)
    gameModeIntervals.push(matrixInterval)
  }

  if (activeGameModes.includes('jumpscare')) {
    // Random jumpscares
    const jumpscareInterval = setInterval(() => {
      if (!activeGameModes.includes('jumpscare') || gameState !== 'playing') {
        clearInterval(jumpscareInterval)
        return
      }

      const now = Date.now()
      // Random chance every 30-60 seconds
      if (now - lastJumpscareTime > 30000 && Math.random() < 0.02) {
        lastJumpscareTime = now
        triggerJumpscare()
      }
    }, 1000)
    gameModeIntervals.push(jumpscareInterval)
  }
}

// Trigger a jumpscare
function triggerJumpscare() {
  const scaryEmojis = ['👻', '💀', '👹', '🎃', '😱', '🤡', '👽', '☠️']
  const emoji = scaryEmojis[Math.floor(Math.random() * scaryEmojis.length)]

  const overlay = document.createElement('div')
  overlay.className = 'jumpscare-overlay'
  overlay.innerHTML = `<span>${emoji}</span>`
  document.body.appendChild(overlay)

  // Play a sound if available
  playSound('capture')

  // Remove after animation
  setTimeout(() => overlay.remove(), 300)
}

// Clear game mode effects
function clearGameModeEffects() {
  gameModeIntervals.forEach(id => clearInterval(id))
  gameModeIntervals = []

  const body = document.body
  body.classList.remove('disco-mode', 'rainbow-mode', 'earthquake-mode', 'giant-mode', 'tiny-mode', 'chaos-mode', 'mirror-mode', 'speed-mode', 'matrix-mode')

  document.querySelectorAll('.game-mode-overlay').forEach(el => el.remove())

  const style = document.getElementById('game-mode-styles')
  if (style) style.remove()
}

// Check and show global messages
async function checkGlobalMessages() {
  if (!getCurrentUser()) return

  pendingGlobalMessages = await getActiveGlobalMessages()
  showNextGlobalMessage()
}

function showNextGlobalMessage() {
  if (pendingGlobalMessages.length === 0) {
    showingGlobalMessage = null
    return
  }

  showingGlobalMessage = pendingGlobalMessages.shift()!
  renderGlobalMessagePopup()
}

function renderGlobalMessagePopup() {
  if (!showingGlobalMessage) return

  // Remove existing popup
  document.getElementById('global-message-popup')?.remove()

  const typeColors = {
    info: 'from-blue-600 to-blue-800',
    warning: 'from-yellow-600 to-yellow-800',
    success: 'from-green-600 to-green-800',
    error: 'from-red-600 to-red-800'
  }

  const typeIcons = {
    info: '📢',
    warning: '⚠️',
    success: '✅',
    error: '❌'
  }

  const popup = document.createElement('div')
  popup.id = 'global-message-popup'
  popup.className = 'fixed inset-0 bg-black/70 flex items-center justify-center z-[10000] p-4'
  popup.innerHTML = `
    <div class="bg-gradient-to-br ${typeColors[showingGlobalMessage.type]} p-6 rounded-xl max-w-md w-full shadow-2xl animate-bounce-in">
      <div class="flex items-center gap-3 mb-4">
        <span class="text-4xl">${typeIcons[showingGlobalMessage.type]}</span>
        <h2 class="text-xl font-bold text-white">Global Message</h2>
      </div>
      <p class="text-white text-lg mb-4">${showingGlobalMessage.message}</p>
      <p class="text-white/70 text-sm mb-4">From: ${showingGlobalMessage.createdBy}</p>
      <button id="dismiss-global-msg" class="w-full bg-white/20 hover:bg-white/30 text-white font-bold py-3 px-6 rounded-lg transition-colors">
        OK
      </button>
    </div>
  `
  document.body.appendChild(popup)

  // Add animation style if not exists
  if (!document.getElementById('global-msg-style')) {
    const style = document.createElement('style')
    style.id = 'global-msg-style'
    style.textContent = `
      @keyframes bounce-in {
        0% { transform: scale(0.5); opacity: 0; }
        50% { transform: scale(1.05); }
        100% { transform: scale(1); opacity: 1; }
      }
      .animate-bounce-in { animation: bounce-in 0.3s ease-out; }
    `
    document.head.appendChild(style)
  }

  document.getElementById('dismiss-global-msg')?.addEventListener('click', async () => {
    if (showingGlobalMessage) {
      await markMessageSeen(showingGlobalMessage.id)
    }
    popup.remove()
    showNextGlobalMessage()
  })
}

// Equipped cosmetics (loaded from user data)
let equippedTheme: string | null = null
let equippedPieceSkin: string | null = null
let equippedEffect: string | null = null
let equippedSoundPack: string | null = null
let equippedMusicPack: string | null = null

// Visual effect particles
interface EffectParticle {
  x: number
  y: number
  vx: number
  vy: number
  life: number
  maxLife: number
  size: number
  color: string
  type: 'fire' | 'smoke' | 'sparkle' | 'heart' | 'star' | 'lightning' | 'ghost'
}
let effectParticles: EffectParticle[] = []

// Get current equipped skin style
function getCurrentSkinStyle(): string | null {
  if (!equippedPieceSkin) return null
  const skin = SHOP_ITEMS.find(i => i.id === equippedPieceSkin)
  return skin?.skinStyle || null
}

// Get skin-adjusted colors for pieces - makes skins actually change piece appearance
function getSkinColors(team: 'yellow' | 'green'): {
  primary: string,
  secondary: string,
  accent: string,
  dark: string,
  helmet: string,
  uniform: string,
  uniformDark: string
} {
  const skinStyle = getCurrentSkinStyle()

  // Default military colors
  const defaultColors = {
    yellow: {
      primary: '#fde047',
      secondary: '#facc15',
      accent: '#eab308',
      dark: '#a16207',
      helmet: '#6b5a2f',
      uniform: '#5c4a1f',
      uniformDark: '#3d3214'
    },
    green: {
      primary: '#4ade80',
      secondary: '#22c55e',
      accent: '#16a34a',
      dark: '#15803d',
      helmet: '#3d5a3d',
      uniform: '#2d4a2d',
      uniformDark: '#1e331e'
    }
  }

  if (!skinStyle) return defaultColors[team]

  // Skin-specific color palettes
  switch (skinStyle) {
    case 'robot':
      return team === 'yellow' ? {
        primary: '#00ffff',      // Cyan
        secondary: '#0891b2',    // Darker cyan
        accent: '#06b6d4',       // Teal
        dark: '#0e7490',         // Dark teal
        helmet: '#1e3a5f',       // Navy blue
        uniform: '#0f172a',      // Dark navy
        uniformDark: '#020617'   // Near black
      } : {
        primary: '#ff00ff',      // Magenta
        secondary: '#a855f7',    // Purple
        accent: '#c026d3',       // Pink
        dark: '#7e22ce',         // Dark purple
        helmet: '#4a1d5f',       // Dark magenta
        uniform: '#1e1b4b',      // Dark indigo
        uniformDark: '#0c0a1d'   // Near black
      }
    case 'medieval':
      return team === 'yellow' ? {
        primary: '#ffd700',      // Gold
        secondary: '#daa520',    // Goldenrod
        accent: '#b8860b',       // Dark goldenrod
        dark: '#8b6914',         // Dark gold
        helmet: '#8b4513',       // Saddle brown
        uniform: '#654321',      // Dark brown
        uniformDark: '#3d2817'   // Very dark brown
      } : {
        primary: '#c0c0c0',      // Silver
        secondary: '#a8a8a8',    // Gray
        accent: '#808080',       // Dark gray
        dark: '#606060',         // Darker gray
        helmet: '#4a4a4a',       // Charcoal
        uniform: '#2d2d2d',      // Dark charcoal
        uniformDark: '#1a1a1a'   // Near black
      }
    case 'scifi':
      return team === 'yellow' ? {
        primary: '#00ff66',      // Neon green
        secondary: '#22c55e',    // Green
        accent: '#10b981',       // Emerald
        dark: '#059669',         // Dark emerald
        helmet: '#064e3b',       // Dark teal
        uniform: '#022c22',      // Very dark teal
        uniformDark: '#011a13'   // Near black
      } : {
        primary: '#00ffff',      // Neon cyan
        secondary: '#06b6d4',    // Cyan
        accent: '#0891b2',       // Teal
        dark: '#0e7490',         // Dark teal
        helmet: '#164e63',       // Dark cyan
        uniform: '#083344',      // Very dark cyan
        uniformDark: '#042f2e'   // Near black
      }
    case 'pixel':
      return team === 'yellow' ? {
        primary: '#ffff00',      // Pure yellow
        secondary: '#ff8800',    // Orange
        accent: '#ff4400',       // Red-orange
        dark: '#cc3300',         // Dark orange
        helmet: '#884400',       // Brown
        uniform: '#664422',      // Dark brown
        uniformDark: '#442211'   // Very dark brown
      } : {
        primary: '#00ff00',      // Pure green
        secondary: '#00cc88',    // Teal green
        accent: '#00aa66',       // Dark teal
        dark: '#008844',         // Forest green
        helmet: '#006633',       // Dark green
        uniform: '#004422',      // Very dark green
        uniformDark: '#002211'   // Near black
      }
    case 'minimal':
      return team === 'yellow' ? {
        primary: '#f5f5f5',      // White
        secondary: '#e5e5e5',    // Light gray
        accent: '#fde047',       // Yellow accent
        dark: '#a3a3a3',         // Gray
        helmet: '#737373',       // Dark gray
        uniform: '#525252',      // Darker gray
        uniformDark: '#404040'   // Very dark gray
      } : {
        primary: '#f5f5f5',      // White
        secondary: '#e5e5e5',    // Light gray
        accent: '#4ade80',       // Green accent
        dark: '#a3a3a3',         // Gray
        helmet: '#737373',       // Dark gray
        uniform: '#525252',      // Darker gray
        uniformDark: '#404040'   // Very dark gray
      }
    case 'cartoon':
      return team === 'yellow' ? {
        primary: '#ffeb3b',      // Bright yellow
        secondary: '#ffc107',    // Amber
        accent: '#ff9800',       // Orange
        dark: '#f57c00',         // Dark orange
        helmet: '#e65100',       // Deep orange
        uniform: '#bf360c',      // Brown orange
        uniformDark: '#8d2600'   // Dark brown
      } : {
        primary: '#8bc34a',      // Light green
        secondary: '#4caf50',    // Green
        accent: '#43a047',       // Medium green
        dark: '#2e7d32',         // Dark green
        helmet: '#1b5e20',       // Very dark green
        uniform: '#194d19',      // Forest
        uniformDark: '#0d3d0d'   // Near black
      }
    case 'military':
      return team === 'yellow' ? {
        primary: '#8b8b00',      // Olive
        secondary: '#6b6b00',    // Dark olive
        accent: '#4b4b00',       // Darker olive
        dark: '#3b3b00',         // Very dark olive
        helmet: '#2d2d00',       // Near black olive
        uniform: '#1f1f00',      // Black olive
        uniformDark: '#0f0f00'   // Near black
      } : {
        primary: '#556b2f',      // Dark olive green
        secondary: '#4a5d2a',    // Olive drab
        accent: '#3d4f22',       // Dark drab
        dark: '#2f3d1a',         // Very dark drab
        helmet: '#222d12',       // Near black
        uniform: '#1a2210',      // Very dark
        uniformDark: '#0f1508'   // Near black
      }
    case 'fantasy':
      return team === 'yellow' ? {
        primary: '#9400d3',      // Purple
        secondary: '#8b008b',    // Dark magenta
        accent: '#800080',       // Purple
        dark: '#4b0082',         // Indigo
        helmet: '#2e0854',       // Dark purple
        uniform: '#1a0330',      // Very dark purple
        uniformDark: '#0d011a'   // Near black
      } : {
        primary: '#00ced1',      // Dark turquoise
        secondary: '#20b2aa',    // Light sea green
        accent: '#008b8b',       // Dark cyan
        dark: '#006666',         // Dark teal
        helmet: '#004d4d',       // Very dark teal
        uniform: '#003333',      // Near black teal
        uniformDark: '#001a1a'   // Near black
      }
    default:
      return defaultColors[team]
  }
}

// Get current equipped effect type
function getCurrentEffectType(): string | null {
  if (!equippedEffect) return null
  const effect = SHOP_ITEMS.find(i => i.id === equippedEffect)
  return effect?.effectType || null
}

// Apply skin style visual effects to a piece SVG
function applySkinStyle(pieceSvg: string, x: number, y: number, team: 'yellow' | 'green'): string {
  const skinStyle = getCurrentSkinStyle()
  if (!skinStyle) return pieceSvg

  let overlayEffects = ''
  let backgroundEffects = ''
  const centerX = x + 25
  const centerY = y + 25
  const teamColor1 = team === 'yellow' ? '#ffff00' : '#00ff00'
  const teamColor2 = team === 'yellow' ? '#ff8800' : '#00cc88'

  switch (skinStyle) {
    case 'robot':
      // Metallic robot frame with glowing elements
      backgroundEffects = `
        <rect x="${x + 5}" y="${y + 5}" width="40" height="40" rx="5" fill="none" stroke="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" stroke-width="3" opacity="0.8" class="pointer-events-none" />
        <rect x="${x + 8}" y="${y + 8}" width="34" height="34" rx="3" fill="${team === 'yellow' ? 'rgba(0,255,255,0.15)' : 'rgba(255,0,255,0.15)'}" class="pointer-events-none" />
      `
      overlayEffects = `
        <circle cx="${x + 12}" cy="${y + 12}" r="4" fill="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" class="pointer-events-none">
          <animate attributeName="opacity" values="1;0.3;1" dur="0.8s" repeatCount="indefinite" />
        </circle>
        <circle cx="${x + 38}" cy="${y + 12}" r="4" fill="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" class="pointer-events-none">
          <animate attributeName="opacity" values="0.3;1;0.3" dur="0.8s" repeatCount="indefinite" />
        </circle>
        <line x1="${x + 12}" y1="${y + 16}" x2="${x + 12}" y2="${y + 38}" stroke="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" stroke-width="2" opacity="0.5" class="pointer-events-none" />
        <line x1="${x + 38}" y1="${y + 16}" x2="${x + 38}" y2="${y + 38}" stroke="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" stroke-width="2" opacity="0.5" class="pointer-events-none" />
        <rect x="${x + 18}" y="${y + 40}" width="14" height="4" fill="${team === 'yellow' ? '#00ffff' : '#ff00ff'}" opacity="0.7" class="pointer-events-none" />
      `
      break
    case 'medieval':
      // Shield and crown effect
      backgroundEffects = `
        <path d="M${centerX} ${y + 2} L${x + 42} ${y + 12} L${x + 42} ${y + 35} L${centerX} ${y + 48} L${x + 8} ${y + 35} L${x + 8} ${y + 12} Z" fill="none" stroke="#ffd700" stroke-width="3" opacity="0.8" class="pointer-events-none" />
        <path d="M${centerX} ${y + 5} L${x + 39} ${y + 14} L${x + 39} ${y + 33} L${centerX} ${y + 44} L${x + 11} ${y + 33} L${x + 11} ${y + 14} Z" fill="rgba(255,215,0,0.15)" class="pointer-events-none" />
      `
      overlayEffects = `
        <path d="M${centerX - 12} ${y} L${centerX - 8} ${y - 6} L${centerX - 4} ${y} L${centerX} ${y - 8} L${centerX + 4} ${y} L${centerX + 8} ${y - 6} L${centerX + 12} ${y}" stroke="#ffd700" fill="#ffd700" stroke-width="2" class="pointer-events-none" />
        <circle cx="${centerX}" cy="${y - 2}" r="2" fill="#ff0000" class="pointer-events-none" />
      `
      break
    case 'scifi':
      // Holographic effect with scan lines
      backgroundEffects = `
        <rect x="${x + 3}" y="${y + 3}" width="44" height="44" rx="3" fill="rgba(0,255,100,0.1)" stroke="#00ff66" stroke-width="2" class="pointer-events-none" />
      `
      overlayEffects = `
        <line x1="${x}" y1="${y + 8}" x2="${x + 50}" y2="${y + 8}" stroke="#00ff66" stroke-width="1" opacity="0.6" class="pointer-events-none">
          <animate attributeName="y1" values="${y + 8};${y + 42};${y + 8}" dur="2s" repeatCount="indefinite" />
          <animate attributeName="y2" values="${y + 8};${y + 42};${y + 8}" dur="2s" repeatCount="indefinite" />
        </line>
        <circle cx="${x + 8}" cy="${y + 8}" r="3" fill="#00ff66" opacity="0.8" class="pointer-events-none" />
        <circle cx="${x + 42}" cy="${y + 8}" r="3" fill="#00ff66" opacity="0.8" class="pointer-events-none" />
        <circle cx="${x + 8}" cy="${y + 42}" r="3" fill="#00ff66" opacity="0.8" class="pointer-events-none" />
        <circle cx="${x + 42}" cy="${y + 42}" r="3" fill="#00ff66" opacity="0.8" class="pointer-events-none" />
        <text x="${x + 5}" y="${y + 48}" font-size="6" fill="#00ff66" font-family="monospace" class="pointer-events-none">SCI-FI</text>
      `
      break
    case 'pixel':
      // Big pixelated frame - very visible!
      const pixelSize = 6
      backgroundEffects = `
        <!-- Pixel border top -->
        <rect x="${x}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + pixelSize}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + pixelSize * 2}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize * 3}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize * 2}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize}" y="${y}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <!-- Pixel border left -->
        <rect x="${x}" y="${y + pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x}" y="${y + pixelSize * 2}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <!-- Pixel border right -->
        <rect x="${x + 50 - pixelSize}" y="${y + pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize}" y="${y + pixelSize * 2}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <!-- Pixel border bottom -->
        <rect x="${x}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + pixelSize}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + pixelSize * 2}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize * 3}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize * 2}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize}" y="${y + 50 - pixelSize}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <!-- Pixel border bottom-left corner -->
        <rect x="${x}" y="${y + 50 - pixelSize * 2}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x}" y="${y + 50 - pixelSize * 3}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
        <!-- Pixel border bottom-right corner -->
        <rect x="${x + 50 - pixelSize}" y="${y + 50 - pixelSize * 2}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor2}" class="pointer-events-none" />
        <rect x="${x + 50 - pixelSize}" y="${y + 50 - pixelSize * 3}" width="${pixelSize}" height="${pixelSize}" fill="${teamColor1}" class="pointer-events-none" />
      `
      overlayEffects = `
        <text x="${centerX}" y="${y + 48}" font-size="8" fill="${teamColor1}" text-anchor="middle" font-family="monospace" font-weight="bold" class="pointer-events-none">8-BIT</text>
      `
      break
    case 'minimal':
      // Clean geometric shapes
      backgroundEffects = `
        <circle cx="${centerX}" cy="${centerY}" r="24" fill="none" stroke="${teamColor1}" stroke-width="3" class="pointer-events-none" />
        <circle cx="${centerX}" cy="${centerY}" r="20" fill="none" stroke="${teamColor2}" stroke-width="1" stroke-dasharray="4,4" class="pointer-events-none" />
      `
      overlayEffects = `
        <line x1="${centerX - 18}" y1="${centerY}" x2="${centerX + 18}" y2="${centerY}" stroke="${teamColor1}" stroke-width="1" opacity="0.5" class="pointer-events-none" />
        <line x1="${centerX}" y1="${centerY - 18}" x2="${centerX}" y2="${centerY + 18}" stroke="${teamColor1}" stroke-width="1" opacity="0.5" class="pointer-events-none" />
      `
      break
    case 'cartoon':
      // Cartoon style with thick outlines and fun effects
      backgroundEffects = `
        <ellipse cx="${centerX + 2}" cy="${centerY + 3}" rx="24" ry="22" fill="rgba(0,0,0,0.3)" class="pointer-events-none" />
        <ellipse cx="${centerX}" cy="${centerY}" rx="24" ry="22" fill="none" stroke="#000000" stroke-width="4" class="pointer-events-none" />
        <ellipse cx="${centerX}" cy="${centerY}" rx="22" ry="20" fill="rgba(255,255,255,0.2)" class="pointer-events-none" />
      `
      overlayEffects = `
        <text x="${x + 40}" y="${y + 12}" font-size="12" class="pointer-events-none">✨</text>
        <text x="${x + 5}" y="${y + 15}" font-size="10" class="pointer-events-none">⭐</text>
        <ellipse cx="${centerX - 8}" cy="${y + 15}" rx="4" ry="6" fill="#ffffff" opacity="0.6" class="pointer-events-none" />
      `
      break
    case 'military':
      // Tactical military look with camo pattern
      backgroundEffects = `
        <rect x="${x + 3}" y="${y + 3}" width="44" height="44" fill="none" stroke="#556b2f" stroke-width="3" class="pointer-events-none" />
        <rect x="${x + 6}" y="${y + 6}" width="38" height="38" fill="none" stroke="#8b4513" stroke-width="1" stroke-dasharray="8,4" class="pointer-events-none" />
      `
      overlayEffects = `
        <circle cx="${centerX}" cy="${centerY}" r="16" fill="none" stroke="#ff0000" stroke-width="2" opacity="0.6" class="pointer-events-none" />
        <line x1="${centerX - 20}" y1="${centerY}" x2="${centerX - 8}" y2="${centerY}" stroke="#ff0000" stroke-width="2" opacity="0.6" class="pointer-events-none" />
        <line x1="${centerX + 8}" y1="${centerY}" x2="${centerX + 20}" y2="${centerY}" stroke="#ff0000" stroke-width="2" opacity="0.6" class="pointer-events-none" />
        <line x1="${centerX}" y1="${centerY - 20}" x2="${centerX}" y2="${centerY - 8}" stroke="#ff0000" stroke-width="2" opacity="0.6" class="pointer-events-none" />
        <line x1="${centerX}" y1="${centerY + 8}" x2="${centerX}" y2="${centerY + 20}" stroke="#ff0000" stroke-width="2" opacity="0.6" class="pointer-events-none" />
        <text x="${x + 3}" y="${y + 48}" font-size="6" fill="#556b2f" font-family="monospace" class="pointer-events-none">TACTICAL</text>
      `
      break
    case 'fantasy':
      // Magical aura with sparkles and glow
      backgroundEffects = `
        <defs>
          <radialGradient id="magicAura${x}${y}" cx="50%" cy="50%" r="50%">
            <stop offset="0%" style="stop-color:${team === 'yellow' ? '#9400d3' : '#00ced1'};stop-opacity:0.4" />
            <stop offset="100%" style="stop-color:${team === 'yellow' ? '#9400d3' : '#00ced1'};stop-opacity:0" />
          </radialGradient>
        </defs>
        <circle cx="${centerX}" cy="${centerY}" r="28" fill="url(#magicAura${x}${y})" class="pointer-events-none">
          <animate attributeName="r" values="28;32;28" dur="1.5s" repeatCount="indefinite" />
        </circle>
        <circle cx="${centerX}" cy="${centerY}" r="24" fill="none" stroke="${team === 'yellow' ? '#9400d3' : '#00ced1'}" stroke-width="2" opacity="0.6" class="pointer-events-none">
          <animate attributeName="stroke-opacity" values="0.6;1;0.6" dur="1s" repeatCount="indefinite" />
        </circle>
      `
      overlayEffects = `
        <text x="${x + 5}" y="${y + 12}" font-size="10" class="pointer-events-none">✨</text>
        <text x="${x + 38}" y="${y + 10}" font-size="12" class="pointer-events-none">⭐</text>
        <text x="${x + 8}" y="${y + 45}" font-size="8" class="pointer-events-none">🔮</text>
        <text x="${x + 35}" y="${y + 48}" font-size="10" class="pointer-events-none">✨</text>
        <text x="${centerX}" y="${y - 2}" font-size="8" text-anchor="middle" fill="${team === 'yellow' ? '#ffd700' : '#00ffff'}" class="pointer-events-none">♦</text>
      `
      break
  }

  return backgroundEffects + pieceSvg + overlayEffects
}

// Spawn effect particles at a position
function spawnEffectParticles(x: number, y: number, count: number = 10) {
  const effectType = getCurrentEffectType()
  if (!effectType) return

  for (let i = 0; i < count; i++) {
    const angle = Math.random() * Math.PI * 2
    const speed = Math.random() * 3 + 1
    let color = '#ff6600'
    let particleType: EffectParticle['type'] = 'fire'
    let size = Math.random() * 4 + 2

    switch (effectType) {
      case 'fire':
        color = ['#ff4500', '#ff6600', '#ff8800', '#ffaa00'][Math.floor(Math.random() * 4)]
        particleType = 'fire'
        break
      case 'lightning':
        color = ['#00ffff', '#ffffff', '#88ffff', '#aaffff'][Math.floor(Math.random() * 4)]
        particleType = 'lightning'
        size = Math.random() * 6 + 3
        break
      case 'sparkle':
        color = ['#ffff00', '#ffffff', '#ffdd00', '#ffffaa'][Math.floor(Math.random() * 4)]
        particleType = 'sparkle'
        size = Math.random() * 3 + 1
        break
      case 'smoke':
        color = ['#555555', '#666666', '#777777', '#888888'][Math.floor(Math.random() * 4)]
        particleType = 'smoke'
        size = Math.random() * 5 + 3
        break
      case 'hearts':
        color = ['#ff0066', '#ff3388', '#ff6699', '#ff99aa'][Math.floor(Math.random() * 4)]
        particleType = 'heart'
        size = Math.random() * 4 + 3
        break
      case 'stars':
        color = ['#ffff00', '#ffaa00', '#ffffff', '#ffdd66'][Math.floor(Math.random() * 4)]
        particleType = 'star'
        size = Math.random() * 4 + 2
        break
      case 'explosion':
        color = ['#ff0000', '#ff4400', '#ff8800', '#ffcc00'][Math.floor(Math.random() * 4)]
        particleType = 'fire'
        size = Math.random() * 6 + 4
        break
      case 'ghost':
        color = ['rgba(200,200,255,0.8)', 'rgba(180,180,255,0.6)', 'rgba(220,220,255,0.7)'][Math.floor(Math.random() * 3)]
        particleType = 'ghost'
        size = Math.random() * 8 + 5
        break
    }

    effectParticles.push({
      x, y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed - (effectType === 'fire' || effectType === 'smoke' ? 2 : 0),
      life: 1,
      maxLife: 1,
      size,
      color,
      type: particleType
    })
  }
}

// Update effect particles (call in animation loop)
function updateEffectParticles(deltaTime: number) {
  effectParticles = effectParticles.filter(p => {
    p.x += p.vx * deltaTime * 60
    p.y += p.vy * deltaTime * 60
    p.life -= deltaTime * 2
    if (p.type === 'fire' || p.type === 'smoke') {
      p.vy -= deltaTime * 3 // Float upward
    }
    if (p.type === 'ghost') {
      p.vx *= 0.98
      p.vy *= 0.98
    }
    return p.life > 0
  })
}

// Render effect particles to SVG
function renderEffectParticles(): string {
  if (effectParticles.length === 0) return ''

  return effectParticles.map(p => {
    const opacity = p.life
    const scale = p.life * 0.5 + 0.5
    const size = p.size * scale

    switch (p.type) {
      case 'fire':
        return `<circle cx="${p.x}" cy="${p.y}" r="${size}" fill="${p.color}" opacity="${opacity}" />`
      case 'smoke':
        return `<circle cx="${p.x}" cy="${p.y}" r="${size}" fill="${p.color}" opacity="${opacity * 0.6}" />`
      case 'sparkle':
        return `<polygon points="${p.x},${p.y - size} ${p.x + size * 0.3},${p.y - size * 0.3} ${p.x + size},${p.y} ${p.x + size * 0.3},${p.y + size * 0.3} ${p.x},${p.y + size} ${p.x - size * 0.3},${p.y + size * 0.3} ${p.x - size},${p.y} ${p.x - size * 0.3},${p.y - size * 0.3}" fill="${p.color}" opacity="${opacity}" />`
      case 'heart':
        return `<text x="${p.x}" y="${p.y}" font-size="${size * 2}" fill="${p.color}" opacity="${opacity}" text-anchor="middle" dominant-baseline="middle">❤</text>`
      case 'star':
        return `<text x="${p.x}" y="${p.y}" font-size="${size * 2}" fill="${p.color}" opacity="${opacity}" text-anchor="middle" dominant-baseline="middle">★</text>`
      case 'lightning':
        return `<line x1="${p.x}" y1="${p.y}" x2="${p.x + (Math.random() - 0.5) * size * 3}" y2="${p.y + (Math.random() - 0.5) * size * 3}" stroke="${p.color}" stroke-width="${size * 0.5}" opacity="${opacity}" />`
      case 'ghost':
        return `<ellipse cx="${p.x}" cy="${p.y}" rx="${size}" ry="${size * 1.2}" fill="${p.color}" opacity="${opacity * 0.5}" />`
      default:
        return `<circle cx="${p.x}" cy="${p.y}" r="${size}" fill="${p.color}" opacity="${opacity}" />`
    }
  }).join('')
}

// Theme ambient effects state
let themeParticles: { x: number; y: number; vx: number; vy: number; size: number; life: number; type: string }[] = []
let lastThemeUpdate = 0

// Render theme-specific ambient effects around board edges
function renderThemeAmbientEffects(totalWidth: number, totalHeight: number): string {
  if (!equippedTheme) return ''

  const now = Date.now()
  const delta = (now - lastThemeUpdate) / 1000
  lastThemeUpdate = now

  // Get theme type from equipped theme
  const themeId = equippedTheme

  // Spawn new particles if needed
  const maxParticles = 30
  if (themeParticles.length < maxParticles && Math.random() > 0.7) {
    spawnThemeParticle(totalWidth, totalHeight, themeId)
  }

  // Update particles
  themeParticles = themeParticles.filter(p => {
    p.x += p.vx * delta * 60
    p.y += p.vy * delta * 60
    p.life -= delta * 0.3

    // Wrap around edges
    if (p.x < -20) p.x = totalWidth + 10
    if (p.x > totalWidth + 20) p.x = -10
    if (p.y < -20) p.y = totalHeight + 10
    if (p.y > totalHeight + 20) p.y = -10

    return p.life > 0
  })

  // Render particles
  return themeParticles.map(p => {
    const opacity = Math.min(1, p.life)

    switch (p.type) {
      case 'sand':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size}" fill="#d4a574" opacity="${opacity * 0.6}" class="pointer-events-none" />`
      case 'snow':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size}" fill="#ffffff" opacity="${opacity * 0.8}" class="pointer-events-none" />`
      case 'leaf':
        return `<ellipse cx="${p.x}" cy="${p.y}" rx="${p.size}" ry="${p.size * 0.5}" fill="#228b22" opacity="${opacity * 0.7}" transform="rotate(${p.life * 360}, ${p.x}, ${p.y})" class="pointer-events-none" />`
      case 'star':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size * 0.5}" fill="#ffffff" opacity="${opacity * (0.5 + Math.sin(now / 200 + p.x) * 0.3)}" class="pointer-events-none" />`
      case 'bubble':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size}" fill="none" stroke="#4fc3f7" stroke-width="1" opacity="${opacity * 0.5}" class="pointer-events-none" />`
      case 'ember':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size}" fill="${Math.random() > 0.5 ? '#ff5722' : '#ff9800'}" opacity="${opacity * 0.8}" class="pointer-events-none" />`
      case 'sparkle':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size * (0.5 + Math.sin(now / 100 + p.y) * 0.5)}" fill="#ff69b4" opacity="${opacity}" class="pointer-events-none" />`
      case 'firefly':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size * (0.5 + Math.sin(now / 150 + p.x * p.y) * 0.5)}" fill="#90ee90" opacity="${opacity * 0.9}" class="pointer-events-none" />`
      case 'ray':
        return `<line x1="${p.x}" y1="${p.y}" x2="${p.x + p.vx * 50}" y2="${p.y + p.vy * 50}" stroke="#ff6347" stroke-width="${p.size * 0.5}" opacity="${opacity * 0.3}" class="pointer-events-none" />`
      case 'neon':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size * (1 + Math.sin(now / 100) * 0.3)}" fill="${['#ff00ff', '#00ffff', '#ffff00'][Math.floor(p.x + p.y) % 3]}" opacity="${opacity * 0.7}" class="pointer-events-none" />`
      case 'gear':
        return `<circle cx="${p.x}" cy="${p.y}" r="${p.size}" fill="none" stroke="#d4af37" stroke-width="2" opacity="${opacity * 0.5}" stroke-dasharray="2 2" transform="rotate(${now / 20 + p.x}, ${p.x}, ${p.y})" class="pointer-events-none" />`
      case 'autumn':
        return `<ellipse cx="${p.x}" cy="${p.y}" rx="${p.size}" ry="${p.size * 0.6}" fill="${['#daa520', '#cd853f', '#8b4513'][Math.floor(p.x) % 3]}" opacity="${opacity * 0.7}" transform="rotate(${p.life * 180}, ${p.x}, ${p.y})" class="pointer-events-none" />`
      default:
        return ''
    }
  }).join('')
}

// Spawn theme-specific particle
function spawnThemeParticle(totalWidth: number, totalHeight: number, themeId: string) {
  const edge = Math.floor(Math.random() * 4) // 0=top, 1=right, 2=bottom, 3=left
  let x = 0, y = 0, vx = 0, vy = 0
  let type = 'sparkle'
  let size = 2 + Math.random() * 4

  // Position at random edge
  switch (edge) {
    case 0: x = Math.random() * totalWidth; y = -10; break
    case 1: x = totalWidth + 10; y = Math.random() * totalHeight; break
    case 2: x = Math.random() * totalWidth; y = totalHeight + 10; break
    case 3: x = -10; y = Math.random() * totalHeight; break
  }

  // Theme-specific particle types and movement
  switch (themeId) {
    case 'theme_desert':
      type = 'sand'
      vx = 1 + Math.random()
      vy = 0.2 + Math.random() * 0.3
      break
    case 'theme_arctic':
    case 'theme_winter':
      type = 'snow'
      vx = Math.random() * 0.5 - 0.25
      vy = 0.5 + Math.random() * 0.5
      size = 2 + Math.random() * 3
      break
    case 'theme_jungle':
    case 'theme_forest':
      type = themeId === 'theme_forest' ? 'firefly' : 'leaf'
      vx = Math.random() * 0.5 - 0.25
      vy = 0.3 + Math.random() * 0.3
      break
    case 'theme_night':
    case 'theme_space':
      type = 'star'
      vx = 0
      vy = 0
      x = Math.random() * totalWidth
      y = Math.random() * totalHeight
      size = 1 + Math.random() * 2
      break
    case 'theme_ocean':
    case 'theme_underwater':
      type = 'bubble'
      vx = Math.random() * 0.3 - 0.15
      vy = -0.3 - Math.random() * 0.3
      break
    case 'theme_lava':
      type = 'ember'
      vx = Math.random() * 0.6 - 0.3
      vy = -0.5 - Math.random() * 0.5
      break
    case 'theme_candy':
      type = 'sparkle'
      vx = Math.random() - 0.5
      vy = Math.random() - 0.5
      break
    case 'theme_sunset':
      type = 'ray'
      vx = 0.5
      vy = 0.3
      x = 0
      y = Math.random() * totalHeight * 0.5
      break
    case 'theme_neon':
      type = 'neon'
      vx = Math.random() - 0.5
      vy = Math.random() - 0.5
      break
    case 'theme_steampunk':
      type = 'gear'
      vx = 0
      vy = 0
      x = 10 + Math.random() * 30
      y = 10 + Math.random() * 30
      size = 5 + Math.random() * 10
      break
    case 'theme_autumn':
      type = 'autumn'
      vx = 0.3 + Math.random() * 0.3
      vy = 0.4 + Math.random() * 0.3
      break
    default:
      return // No effect for unknown themes
  }

  themeParticles.push({ x, y, vx, vy, size, life: 1 + Math.random() * 2, type })
}

