// Theme color palettes
function getThemeColors(): { light: string; dark: string } {
  // Check for equipped shop theme first
  if (equippedTheme) {
    const shopTheme = SHOP_ITEMS.find(i => i.id === equippedTheme && i.colors)
    if (shopTheme?.colors) {
      return { light: shopTheme.colors.light, dark: shopTheme.colors.dark }
    }
  }

  switch (boardTheme) {
    case 'dark':
      return { light: '#4a5568', dark: '#2d3748' }
    case 'light':
      return { light: '#e2e8f0', dark: '#cbd5e0' }
    case 'wood':
      return { light: '#d4a574', dark: '#8b6914' }
    case 'classic':
    default:
      return { light: '#86a876', dark: '#d4c87a' }
  }
}

// Team colors (colorblind-friendly alternatives)
function getTeamColor(team: 'yellow' | 'green'): string {
  // Check for equipped piece skin first - use skin colors
  const skinStyle = getCurrentSkinStyle()
  if (skinStyle) {
    const skinColors = getSkinColors(team)
    return skinColors.primary
  }

  // Check for equipped piece skin with pieceColor (legacy support)
  if (equippedPieceSkin) {
    const shopSkin = SHOP_ITEMS.find(i => i.id === equippedPieceSkin && i.pieceColor)
    if (shopSkin?.pieceColor) {
      return team === 'yellow' ? shopSkin.pieceColor.yellow : shopSkin.pieceColor.green
    }
  }

  if (colorBlindMode) {
    // Blue vs Orange - more distinguishable
    return team === 'yellow' ? '#f97316' : '#3b82f6'
  }
  return team === 'yellow' ? '#eab308' : '#22c55e'
}

function getTeamBgColor(team: 'yellow' | 'green'): string {
  if (colorBlindMode) {
    return team === 'yellow' ? 'bg-orange-500' : 'bg-blue-500'
  }
  return team === 'yellow' ? 'bg-yellow-500' : 'bg-green-500'
}

function getTeamTextColor(team: 'yellow' | 'green'): string {
  if (colorBlindMode) {
    return team === 'yellow' ? 'text-orange-500' : 'text-blue-500'
  }
  return team === 'yellow' ? 'text-yellow-500' : 'text-green-500'
}

// Animation duration based on speed setting
